[{"fieldname": "print_heading_template", "fieldtype": "Custom HTML", "options": " "}, {"fieldtype": "Section Break", "label": ""}, {"fieldtype": "Column Break"}, {"fieldname": "_custom_html", "print_hide": 0, "label": "Custom HTML", "fieldtype": "HTML", "options": "<!DOCTYPE html>
<html>
<head>
    <title>Transaction Receipt</title>
    <style>
        @page {
            size: 80mm 297mm; /* Narrow width for receipt printers */
            margin: 0;
        }
        body {
            margin: 0;
            padding: 0;
            font-family: Arial, sans-serif;
            width: 80mm;
            font-size: 12px;
        }
        .receipt {
            padding: 2mm 5mm;
            page-break-after: always;
        }
        .receipt-copy {
            background-color: #f5f5f5;
            padding-bottom: 10mm;
        }
        .letterhead {
            text-align: center;
            padding: 2mm 0;
            border-bottom: 1px solid #003366;
            margin-bottom: 3mm;
        }
        .letterhead h1 {
            color: #003366;
            margin: 1mm 0;
            font-size: 14px;
        }
        .letterhead p {
            margin: 1mm 0;
            font-size: 9px;
            color: #555;
        }
        .header-container {
            display: flex;
            justify-content: space-between;
            margin-bottom: 3mm;
        }
        .transaction-info {
            font-size: 10px;
        }
        .transaction-id {
            color: red;
            font-weight: bold;
        }
        table {
            width: 100%;
            border-collapse: collapse;
            margin: 3mm 0;
            font-size: 10px;
        }
        th, td {
            border: 1px solid #ddd;
            padding: 2mm;
            text-align: left;
        }
        th {
            background-color: #f2f2f2;
            font-size: 10px;
        }
        .footer-details {
            margin-top: 3mm;
            font-size: 9px;
        }
        .signature-section {
            margin-top: 5mm;
            border-top: 1px dashed #ccc;
            padding-top: 3mm;
        }
        .signature-line {
            display: inline-block;
            width: 40mm;
            border-bottom: 1px solid #333;
            margin-bottom: 1mm;
        }
        .copy-label {
            text-align: right;
            font-weight: bold;
            color: #666;
            font-size: 10px;
            margin-top: 2mm;
        }
        .divider {
            text-align: center;
            padding: 1mm 0;
            font-weight: bold;
            color: #666;
            font-size: 9px;
            background: white;
            border-top: 1px dashed #999;
            border-bottom: 1px dashed #999;
        }
    </style>
</head>
<body>
    <!-- Original Receipt (Top) -->
    <div class="receipt">
        <div class="letterhead">
            <h1>TYCHE CONNECT</h1>
            <p>1 LETHAN ROAD, AVONDALE, HARARE, ZIMBABWE</p>
            <p>Tel: +263 242 123456 | Email: info@tycheconnect.co.zw</p>
        </div>

        <div class="header-container">
            <span class="transaction-info">Transaction ID: <span class="transaction-id">{{doc.name}}</span></span>
            <span class="transaction-info">Date: {{ frappe.utils.now_datetime().strftime("%d-%b-%Y") }}</span>
        </div>

        <table>
            <thead>
                <tr>
                    <th colspan="2">TRANSACTION DETAILS</th>
                </tr>
            </thead>
            <tbody>
                <tr>
                    <td><strong>Sender Name:</strong></td>
                    <td>{{doc.sender_name or ""}}</td>
                </tr>
                <tr>
                    <td><strong>Sender ID:</strong></td>
                    <td>{{doc.identification_number or ""}}</td>
                </tr>
                <tr>
                    <td><strong>Amount Sent:</strong></td>
                    <td>{{doc.amount or ""}}</td>
                </tr>
                <tr>
                    <td><strong>Receiver Name:</strong></td>
                    <td>{{doc.receiver_name or ""}}</td>
                </tr>
                <tr>
                    <td><strong>Receiver ID:</strong></td>
                    <td>{{doc.receiver_id or ""}}</td>
                </tr>
                <tr>
                    <td><strong>Amount Received:</strong></td>
                    <td>{{doc.receiver_amount or ""}}</td>
                </tr>
            </tbody>
        </table>

        <div class="footer-details">
            <p><strong>Processed By:</strong> {{ doc.withdrawn_by or "" }}</p>
            <p><strong>Branch:</strong> {{ doc.withdrawn_branch or "" }}</p>
            <p><strong>Till:</strong> {{ doc.withdrawn_till or "" }}</p>

            <div class="signature-section">
                <p><strong>TELLER'S SIGNATURE:</strong></p>
                <div class="signature-line"></div>

                <p style="margin-top: 3mm;"><strong>CUSTOMER'S SIGNATURE:</strong></p>
                <div class="signature-line"></div>
            </div>

            <p style="text-align: center; margin-top: 3mm;">
                <small>Printed: {{ frappe.utils.now_datetime().strftime("%Y-%m-%d %H:%M:%S") }}</small>
            </p>
        </div>
    </div>

    <!-- Divider with instructions -->
    <div class="divider">
        - - - - - - - CUT HERE - - - - - - -
    </div>

    <!-- Customer Receipt (Bottom) -->
    <div class="receipt receipt-copy">
        <div class="letterhead">
            <h1>TYCHE CONNECT</h1>
            <p>1 LETHAN ROAD, AVONDALE, HARARE, ZIMBABWE</p>
            <p>Tel: +263 242 123456 | Email: info@tycheconnect.co.zw</p>
        </div>

        <div class="header-container">
            <span class="transaction-info">Transaction ID: <span class="transaction-id">{{doc.name}}</span></span>
            <span class="transaction-info">Date: {{ frappe.utils.now_datetime().strftime("%d-%b-%Y") }}</span>
        </div>

        <table>
            <thead>
                <tr>
                    <th colspan="2">TRANSACTION DETAILS</th>
                </tr>
            </thead>
            <tbody>
                <tr>
                    <td><strong>Sender Name:</strong></td>
                    <td>{{doc.sender_name or ""}}</td>
                </tr>
                <tr>
                    <td><strong>Sender ID:</strong></td>
                    <td>{{doc.identification_number or ""}}</td>
                </tr>
                <tr>
                    <td><strong>Amount Sent:</strong></td>
                    <td>{{doc.amount or ""}}</td>
                </tr>
                <tr>
                    <td><strong>Receiver Name:</strong></td>
                    <td>{{doc.receiver_name or ""}}</td>
                </tr>
                <tr>
                    <td><strong>Receiver ID:</strong></td>
                    <td>{{doc.receiver_id or ""}}</td>
                </tr>
                <tr>
                    <td><strong>Amount Received:</strong></td>
                    <td>{{doc.receiver_amount or ""}}</td>
                </tr>
            </tbody>
        </table>

        <div class="footer-details">
            <p><strong>Processed By:</strong> {{ doc.withdrawn_by or "" }}</p>
            <p><strong>Branch:</strong> {{ doc.withdrawn_branch or "" }}</p>
            <p><strong>Till:</strong> {{ doc.withdrawn_till or "" }}</p>

            <div class="signature-section">
                <p><strong>TELLER'S SIGNATURE:</strong></p>
                <div class="signature-line"></div>

                <p style="margin-top: 3mm;"><strong>CUSTOMER'S SIGNATURE:</strong></p>
                <div class="signature-line"></div>
            </div>

            <p style="text-align: center; margin-top: 3mm;">
                <small>Printed: {{ frappe.utils.now_datetime().strftime("%Y-%m-%d %H:%M:%S") }}</small>
            </p>
            <div class="copy-label">CUSTOMER COPY</div>
        </div>
    </div>
</body>
</html>"}]
